var rabbitmq = require("amqplib");
var r = require("rethinkdbdash").connection({
  host: "127.0.0.1", 
  port : 28015, db:'event-driven' });
r.table('orders').changes().run(function(err, cursor){
    if (err) {
      throw err;
    }
    return cursor.each(function(err, row) {
      r.table("orders")
        .insert({
        id: row.new_val.id,
        status: 'processed',
        customername :row.new_val.customername }).run();
    });
});